// Sample pricing data — current vs previous snapshot.
// In production: fetch competitor pricing pages via HTTP Request and diff against stored snapshot.
const snapshots = [
  {
    competitor: 'CompetitorX',
    url: 'https://competitorx.com/pricing',
    previous: {
      captured_at: '2026-07-07',
      plans: [
        { name: 'Starter', price_monthly: 29, price_annual_monthly: 24, features: ['5 users', '10 projects', 'Basic reporting'] },
        { name: 'Pro', price_monthly: 79, price_annual_monthly: 65, features: ['25 users', 'Unlimited projects', 'Advanced reporting', 'API access'] },
        { name: 'Enterprise', price_monthly: null, price_annual_monthly: null, features: ['Unlimited users', 'SSO', 'SLA', 'Custom contract'], contact_sales: true }
      ]
    },
    current: {
      captured_at: '2026-07-14',
      plans: [
        { name: 'Starter', price_monthly: 29, price_annual_monthly: 24, features: ['5 users', '10 projects', 'Basic reporting'] },
        { name: 'Pro', price_monthly: 63, price_annual_monthly: 52, features: ['25 users', 'Unlimited projects', 'Advanced reporting', 'API access', 'AI assistant (beta)'] },
        { name: 'Enterprise', price_monthly: null, price_annual_monthly: null, features: ['Unlimited users', 'SSO', 'SLA', 'Custom contract'], contact_sales: true }
      ]
    }
  },
  {
    competitor: 'CompetitorY',
    url: 'https://competitory.com/pricing',
    previous: {
      captured_at: '2026-07-07',
      plans: [
        { name: 'Free', price_monthly: 0, price_annual_monthly: 0, features: ['3 users', '5 projects'] },
        { name: 'Growth', price_monthly: 49, price_annual_monthly: 39, features: ['15 users', 'Unlimited projects'] },
        { name: 'Business', price_monthly: 129, price_annual_monthly: 99, features: ['50 users', 'Analytics', 'Priority support'] }
      ]
    },
    current: {
      captured_at: '2026-07-14',
      plans: [
        { name: 'Free', price_monthly: 0, price_annual_monthly: 0, features: ['3 users', '5 projects'] },
        { name: 'Growth', price_monthly: 49, price_annual_monthly: 39, features: ['15 users', 'Unlimited projects'] },
        { name: 'Business', price_monthly: 129, price_annual_monthly: 99, features: ['50 users', 'Analytics', 'Priority support'] }
      ]
    }
  }
];
return [{ json: { snapshots, run_at: new Date().toISOString() } }];

// Compute diff between previous and current snapshots.
const { snapshots, run_at } = $input.first().json;
const diffs = [];
for (const s of snapshots) {
  const changes = [];
  const prevPlans = {};
  for (const p of (s.previous?.plans || [])) prevPlans[p.name] = p;
  for (const curr of (s.current?.plans || [])) {
    const prev = prevPlans[curr.name];
    if (!prev) { changes.push({ type: 'new_plan', plan: curr.name, detail: `New plan added at $${curr.price_monthly || 0}/mo` }); continue; }
    if (prev.price_monthly !== curr.price_monthly) {
      const direction = curr.price_monthly < prev.price_monthly ? 'decrease' : 'increase';
      changes.push({ type: 'price_change', plan: curr.name, direction, prev_price: prev.price_monthly, new_price: curr.price_monthly, pct_change: prev.price_monthly ? Math.round(((curr.price_monthly - prev.price_monthly)/prev.price_monthly)*100) : null });
    }
    const prevFeats = new Set(prev.features || []);
    const currFeats = new Set(curr.features || []);
    for (const f of currFeats) if (!prevFeats.has(f)) changes.push({ type: 'feature_added', plan: curr.name, feature: f });
    for (const f of prevFeats) if (!currFeats.has(f)) changes.push({ type: 'feature_removed', plan: curr.name, feature: f });
  }
  diffs.push({ competitor: s.competitor, url: s.url, changes, has_changes: changes.length > 0, previous_date: s.previous?.captured_at, current_date: s.current?.captured_at });
}
const total_changes = diffs.reduce((sum, d) => sum + d.changes.length, 0);
return [{ json: { diffs, total_changes, run_at } }];

const { diffs, total_changes, run_at } = $input.first().json;
const diffText = diffs.filter(d => d.has_changes).map(d =>
  `Competitor: ${d.competitor}\nChanges (${d.changes.length}):` +
  d.changes.map(c => {
    if (c.type === 'price_change') return `  - ${c.plan}: price ${c.direction} from $${c.prev_price} to $${c.new_price}/mo (${c.pct_change > 0 ? '+' : ''}${c.pct_change}%)`;
    if (c.type === 'feature_added') return `  - ${c.plan}: feature added: "${c.feature}"`;
    if (c.type === 'feature_removed') return `  - ${c.plan}: feature removed: "${c.feature}"`;
    if (c.type === 'new_plan') return `  - ${c.detail}`;
    return `  - ${c.type}: ${JSON.stringify(c)}`;
  }).join('\n')
).join('\n\n');
const system = `You are a pricing strategist. You analyse competitor pricing changes and explain their competitive implications concisely. Return ONLY valid JSON.`;
const user = `Analyse these competitor pricing changes detected this week and explain their implications.

${diffText}

Return JSON:
{
  "change_summaries": [
    { "competitor": "string", "headline": "string — one sentence summary of what changed", "implication": "string — what this means for us", "recommended_response": "string", "urgency": "immediate|this-week|this-quarter|monitor" }
  ],
  "aggregate_assessment": "string — 2-3 sentences overall",
  "confidence": "low|medium|high"
}`;
return [{ json: { ...($input.first().json), system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Implications Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.change_summaries || !Array.isArray(parsed.change_summaries)) {
  return [{ json: { _error: true, reason: 'Missing change_summaries' } }];
}
return [{ json: { _error: false, analysis: parsed, diffs: upstream.diffs, total_changes: upstream.total_changes, run_at: upstream.run_at } }];

const { analysis: a, diffs, total_changes, run_at } = $input.first().json;
const changeLines = (a.change_summaries || []).map(c =>
  `  ${c.competitor}: ${c.headline}\n  Implication: ${c.implication}\n  Response: ${c.recommended_response} [${c.urgency}]`
).join('\n\n');
const rawLines = diffs.filter(d => d.has_changes).map(d =>
  `${d.competitor} raw changes:\n` + d.changes.map(c => `  - ${c.type}: ${JSON.stringify(c)}`).join('\n')
).join('\n\n');
const report = [
  `COMPETITIVE PRICING MONITOR`,
  `Run: ${run_at} | Total changes detected: ${total_changes}`,
  ``,
  `ASSESSMENT: ${a.aggregate_assessment}`,
  `Confidence: ${a.confidence}`,
  ``,
  `CHANGE ANALYSIS:`,
  changeLines || '  (none)',
  ``,
  `RAW CHANGES:`,
  rawLines || '  (none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
